// UploadBills.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function UploadBills({ employee }) {
  const navigate = useNavigate();
  const [files, setFiles] = useState(null);
  const [billList, setBillList] = useState([]);

  useEffect(() => {
    if (employee) loadBills();
  }, [employee]);

  const loadBills = async () => {
    const empId = employee.empId || employee.empld;

    const res = await fetch(`${apiBase}/bills?empId=${empId}`);
    const data = await res.json();
    setBillList(Array.isArray(data) ? data : []);
  };

  const handleUpload = async () => {
    if (!files || files.length === 0) return alert("Select files first.");

    const fd = new FormData();
    const empId = employee.empId || employee.empld;

    for (let f of files) fd.append("bills", f);
    fd.append("empId", empId);

    const res = await fetch(`${apiBase}/upload-bills`, {
      method: "POST",
      body: fd,
    });

    const data = await res.json();

    if (data.success) {
      alert("Bills uploaded!");
      loadBills();
      setFiles(null);
    }
  };

  const deleteBill = async (id) => {
    if (!window.confirm("Delete this bill?")) return;

    const res = await fetch(`${apiBase}/bills/${id}`, {
      method: "DELETE",
    });

    const data = await res.json();

    if (data.success) {
      loadBills();
    }
  };

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button style={backBtn} onClick={() => navigate("/tools")}>⬅ Back</button>
          <h2 style={title}>Upload Bills</h2>
        </div>

        <p style={empInfo}>
          {employee.name} • {employee.empId || employee.empld}
        </p>

        <div style={uploadBox}>
          <input type="file" multiple onChange={(e) => setFiles(e.target.files)} />
          <button style={uploadBtn} onClick={handleUpload}>Upload</button>
        </div>

        <h3 style={{ color: green, marginTop: 20 }}>Uploaded Bills</h3>

        {billList.length === 0 ? (
          <p>No bills uploaded yet.</p>
        ) : (
          <table style={table}>
            <thead>
              <tr>
                <th>Date</th>
                <th>File</th>
                <th>Preview</th>
                <th>Delete</th>
              </tr>
            </thead>

            <tbody>
              {billList.map((b) => (
                <tr key={b.id}>
                  <td>{b.uploaded_at?.split?.("T")?.[0]}</td>
                  <td>{b.file_name}</td>
                  <td>
                    <a href={`${apiBase}${b.file_path}`} target="_blank">Open</a>
                  </td>
                  <td>
                    <button style={deleteBtn} onClick={() => deleteBill(b.id)}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
